mapper.select:
select temp2.author_id as tool_author_id, temp2.tool_id as tool_tool_id from (select temp1.tool_id, temp1.author_id, row_number() over (partition by temp1.tool_id, temp1.author_id) as rn2 from (select temp0.* from (select *, row_number() over (partition by t_b_tool_main.tool_id, t_b_tool_main.author_id order by t_b_tool_main.id desc) as rn1 from t_b_tool_main
and t_b_tool_main.deleted = 0 and t_b_tool_main.publish != 0 and t_b_tool_main.review = 'PASS'
and t_b_tool_main.platform = #{platform}
) as temp0 where temp0.rn1 = 1 ) as temp1 left join json_table(json_extract(temp1.keywords, '$[*]'), '$[*]' columns (keyword varchar(50) path '$')) as tk on true
and ( temp1.name like concat('%', #{searchValue}, '%') or tk.keyword like concat('%', #{searchValue}, '%') )
order by instr(temp1.name, #{searchValue}) = 0, char_length(temp1.name), instr(temp1.name, #{searchValue}), instr(tk.keyword, #{searchValue}) = 0, char_length(tk.keyword), instr(tk.keyword, #{searchValue})
order by temp1.publish desc
) as temp2 where temp2.rn2 = 1

select tbtm.id as tool_id, tbtm.name as tool_name, tbtm.tool_id as tool_tool_id, tbtm.icon as tool_icon, tbtm.platform as tool_platform, tbtm.description as tool_description, tbtm.base_id as tool_base_id, tbtm.base_version as tool_base_version, tbtm.author_id as tool_author_id, tbtm.ver as tool_ver, tbtm.keywords as tool_keywords, tbtm.source_id as tool_source_id, tbtm.dist_id as tool_dist_id, tbtm.entry_point as tool_entry_point, tbtm.publish as tool_publish, tbtm.review as tool_review, tbtm.create_time as tool_create_time, tbtm.update_time as tool_update_time, tbtm.deleted as tool_deleted, tbtm.version as tool_version, tsu.id as user_id, tsu.username as user_username, tsui.id as user_info_id, tsui.nickname as user_info_nickname, tsui.avatar as user_info_avatar, tbtc.id as tool_category_id, tbtc.name as tool_category_name, tbtc.enable as tool_category_enable, tbtc.create_time as tool_category_create_time, tbtc.update_time as tool_category_update_time, tbtc.deleted as tool_category_deleted, tbtc.version as tool_category_version, if(tbtf.id is null, 0, 1) as tool_favorite from (select *, row_number() over (partition by t_b_tool_main.tool_id, t_b_tool_main.author_id, t_b_tool_main.platform order by t_b_tool_main.publish desc) as rn from t_b_tool_main where deleted = 0 and t_b_tool_main.publish != 0 and t_b_tool_main.review = 'PASS' ) as tbtm left join t_s_user as tsu on tsu.deleted = 0 and tsu.id = tbtm.author_id left join t_s_user_info as tsui on tsui.deleted = 0 and tsui.user_id = tbtm.author_id left join t_r_tool_main_category as trtmc on trtmc.deleted = 0 and tbtm.id = trtmc.tool_id left join t_b_tool_category as tbtc on tbtc.deleted = 0 and tbtc.enable = 1 and tbtc.id = trtmc.category_id left join t_b_tool_favorite as tbtf on tbtf.deleted = 0 and tbtf.user_id = #{operator} and tbtf.author_id = tbtm.author_id and tbtf.tool_id = tbtm.tool_id
and tbtm.rn = 1
and tbtm.platform = #{platform}
#{item.authorId}, #{item.toolId}
when tbtm.author_id = #{item.authorId} and tbtm.tool_id = #{item.toolId} then #{index}
